final:
module RefModule (
    input [7:0] packet_in,
    output reg accept
);
  wire [7:0] _tap_packet_in = packet_in & {8{1'b1}};

    parameter FILTER_VALUE = 8'b10101010;

    always @(*) begin
        if (packet_in == FILTER_VALUE)
            accept = 1;
        else
            accept = 0;
    end
endmodule
